import os
import psycopg2
from psycopg2.extras import execute_values


def get_connection():
    return psycopg2.connect(os.environ["DATABASE_URL"])


def create_state_ag_profiles(conn):
    with conn.cursor() as cur:
        cur.execute("""
            CREATE TABLE IF NOT EXISTS state_ag_profiles (
                id SERIAL PRIMARY KEY,
                state_name TEXT UNIQUE NOT NULL,
                abbreviation TEXT NOT NULL,
                usda_region TEXT,
                climate_zones TEXT,
                growing_season_start TEXT,
                growing_season_end TEXT,
                annual_precipitation_inches REAL,
                top_commodities TEXT,
                total_farms INTEGER,
                avg_farm_size_acres INTEGER,
                total_ag_revenue TEXT,
                ag_percentage_of_gdp REAL,
                primary_soil_types TEXT,
                hardiness_zones TEXT
            );
        """)
    conn.commit()


